import time
import serial
import prmrpc.rpc_client as uartRPC
from rtrpc.tcpClient import TcpClient
from rtrpc.rpc_client import RPCClientWrapper


class rtUart(object):

    def __init__(self, portName, baudrate, timeout_s=10):
        self.Tx_Flush_Wait = 0.001
        self.Tx_Length = 16
        self.debug = True
        self.portname = portName
        self.baudrate = baudrate
        self.port = serial.Serial(portName, baudrate, timeout=timeout_s)
        self.port.flush()


    def _sendCmd(self, cmd):
        '''
        cmd: string
        '''
        # self.readDump()  # input channel buffer MUST be empty before sending a new command
        MAX_TX_BURST = self.Tx_Length
        if self.port.is_open:
            cmd = cmd + '\r\n'
            txdata = bytearray(cmd, encoding='utf-8')
            print(cmd)
            # txdata.append(0x0d)
            # txdata.append(0x0a)
            # if self.debug: print(txdata)
            while txdata:
                if len(txdata) > MAX_TX_BURST:
                    self.port.write(txdata[:MAX_TX_BURST])
                    self.port.flush()
                    time.sleep(self.Tx_Flush_Wait)
                else:
                    self.port.write(txdata)
                    self.port.flush()
                    time.sleep(self.Tx_Flush_Wait)
                    break
                txdata = txdata[MAX_TX_BURST:]
        else:
            raise RuntimeError("Serial port %s is closed", self.portname)
        return
    
    def _readResponse(self, terminator, timeout=10000):
        '''
        timeout: in second, maximumreadResponse delay of receiving a command response
        '''
        if self.port.is_open:
            rxdata = bytearray(b'')
            timeBegin = time.time()
            while ((time.time() - timeBegin) < timeout/1000.0):
                data = self.port.read_all()
                if data:
                    rxdata += bytearray(data)
                    if rxdata.rfind(terminator.encode()) >= 0:
                    # if (rxdata[-len(terminator):] == terminator):
                        break
            else:
                print("Command response timeout")
            if self.debug: print(rxdata)
        else:
            raise RuntimeError("Serial port %s is closed", self.portname)
        rxdata = rxdata.decode('utf-8')
        return rxdata


    def send_read(self, cmd, terminator, timeout=2000):
        self._sendCmd(cmd)
        return self._readResponse(terminator, timeout)
    
    def close(self):
        self.port.close()
        
        



class rtAbstractRPC(object):

    def __init__(self, publisher=None):
        self.publisher = publisher
        self.port = None
        self.client = None

    def open(self, configInfo):
        # print(configInfo)
        if configInfo:
            _type = configInfo.get("type")
            if _type == "uart":
                portName = configInfo.get("portname")
                baudrate = configInfo.get("baudrate")
                # databits = self._configInfo.get("")
                # parity = self._configInfo.get
                # stopbits = self._configInfo.get
                self.port = rtUart(portName, baudrate)
                self.client = uartRPC.RPCClientWrapper(self.port)
                return True
            elif _type == "tcp":
                ip = configInfo.get("ip")
                port = configInfo.get("port")
                self.port = TcpClient(ip, port, self.publisher)
                self.client = RPCClientWrapper(self.port, self.publisher)
                return True
            else:
                return False
        return False
    
    def close(self):
        try:
            self.port.shutdown()
        except:
            self.port.close()
        del self.port
        self.port = None

    def rpc_call(self, method, *args, **kwargs):
        r = self.client.call(method, *args, **kwargs)
        print(r)
        try:
            return r.result
        except:
            return r.error
